<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Le Record de Trésorerie de Canaan face au Compte à Rebours du Nasdaq</text>
  <g font-family="sans-serif">
    <rect x="20" y="54" width="310" height="330" rx="10" fill="#14283f" stroke="#38bdf8" stroke-width="1.6"/>
